import{_ as t,c as s,o as r,aj as a}from"./chunks/framework.guNMSiFm.js";const d=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"help/overview.md","filePath":"help/overview.md","lastUpdated":1777621302000}'),o={name:"help/overview.md"};function i(h,e,n,l,c,p){return r(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><p>This section is intended to help if you encounter issues while working with Iroha. If something goes wrong, please <a href="#check-the-keys">check the keys</a> first. If that doesn&#39;t help, check the troubleshooting instructions for each stage:</p><ul><li><a href="./installation-issues.html">Installation issues</a></li><li><a href="./configuration-issues.html">Configuration issues</a></li><li><a href="./deployment-issues.html">Deployment issues</a></li><li><a href="./integration-issues.html">Integration issues</a></li></ul><p>If the issue you are experiencing is not described here, contact us via <a href="https://t.me/hyperledgeriroha" target="_blank" rel="noreferrer">Telegram</a>.</p><h2 id="check-the-keys" tabindex="-1">Check the keys <a class="header-anchor" href="#check-the-keys" aria-label="Permalink to &quot;Check the keys&quot;">​</a></h2><p>Most issues arise as a result of unmatched keys. This is why we recommend to follow this rule: <strong>If something goes wrong, check the keys first</strong>.</p><p>Here&#39;s a quick explanation: It is not possible to differentiate the error messages that arise when peers&#39; keys do not match the keys in the array of trusted peers because it would expose the peers&#39; public key. As such, if you have Helm charts or Kubernetes deployments with keys defined via environment variables, compare the configured <a href="/iroha-2-docs/reference/peer-config/params.html#param-public-key"><code>public_key</code></a>, <a href="/iroha-2-docs/reference/peer-config/params.html#param-private-key"><code>private_key</code></a>, and <a href="/iroha-2-docs/reference/peer-config/params.html#param-trusted-peers"><code>trusted_peers</code></a> values before investigating higher-level failures.</p><p>If in doubt, <a href="/iroha-2-docs/guide/security/generating-cryptographic-keys.html">generate a new pair of keys</a>.</p>',8)])])}const f=t(o,[["render",i]]);export{d as __pageData,f as default};
